1	//! The channel interface.
2	
3	use alloc::sync::Arc;
4	use core::{
5	    fmt,
6	    iter::FusedIterator,
7	    mem,
8	    panic::{RefUnwindSafe, UnwindSafe},
9	    time::Duration,
10	};
11	use std::time::Instant;
12	
13	use crate::{
14	    context::Context,
15	    counter,
16	    err::{RecvError, RecvTimeoutError, SendError, SendTimeoutError, TryRecvError, TrySendError},
17	    flavors,
18	    select::{Operation, SelectHandle, Token},
19	};
20	
21	/// Creates a multi-producer multi-consumer channel of unbounded capacity.
22	///
23	/// This channel has a growable buffer that can hold any number of messages at a time.
24	///
25	/// For more info on how to use the channel see [module level documentation](index.html).
26	///
27	/// # Examples
28	///
29	/// ```
30	/// use std::thread;
31	/// use crossbeam_channel::unbounded;
32	///
33	/// let (s, r) = unbounded();
34	///
35	/// // Computes the n-th Fibonacci number.
36	/// fn fib(n: i32) -> i32 {
37	///     if n <= 1 {
38	///         n
39	///     } else {
40	///         fib(n - 1) + fib(n - 2)
41	///     }
42	/// }
43	///
44	/// // Spawn an asynchronous computation.
45	/// thread::spawn(move || s.send(fib(20)).unwrap());
46	///
47	/// // Print the result of the computation.
48	/// println!("{}", r.recv().unwrap());
49	/// ```
50	pub fn unbounded<T>() -> (Sender<T>, Receiver<T>) {
51	    let (s, r) = counter::new(flavors::list::Channel::new());
52	    let s = Sender {
53	        flavor: SenderFlavor::List(s),
54	    };
55	    let r = Receiver {
56	        flavor: ReceiverFlavor::List(r),
57	    };
58	    (s, r)
59	}
60	
61	/// Creates a multi-producer multi-consumer channel of bounded capacity.
62	///
63	/// This channel has a buffer that can hold at most `cap` messages at a time.
64	///
65	/// A special case is zero-capacity channel, which cannot hold any messages. Instead, send and
66	/// receive operations must appear at the same time in order to pair up and pass the message over.
67	///
68	/// For more info on how to use the channel see [module level documentation](index.html).
69	///
70	/// # Examples
71	///
72	/// A channel of capacity 1:
73	///
74	/// ```
75	/// use std::thread;
76	/// use std::time::Duration;
77	/// use crossbeam_channel::bounded;
78	///
79	/// let (s, r) = bounded(1);
80	///
81	/// // This call returns immediately because there is enough space in the channel.
82	/// s.send(1).unwrap();
83	///
84	/// thread::spawn(move || {
85	///     // This call blocks the current thread because the channel is full.
86	///     // It will be able to complete only after the first message is received.
87	///     s.send(2).unwrap();
88	/// });
89	///
90	/// thread::sleep(Duration::from_secs(1));
91	/// assert_eq!(r.recv(), Ok(1));
92	/// assert_eq!(r.recv(), Ok(2));
93	/// ```
94	///
95	/// A zero-capacity channel:
96	///
97	/// ```
98	/// use std::thread;
99	/// use std::time::Duration;
100	/// use crossbeam_channel::bounded;
101	///
102	/// let (s, r) = bounded(0);
103	///
104	/// thread::spawn(move || {
105	///     // This call blocks the current thread until a receive operation appears
106	///     // on the other side of the channel.
107	///     s.send(1).unwrap();
108	/// });
109	///
110	/// thread::sleep(Duration::from_secs(1));
111	/// assert_eq!(r.recv(), Ok(1));
112	/// ```
113	pub fn bounded<T>(cap: usize) -> (Sender<T>, Receiver<T>) {
114	    if cap == 0 {
115	        let (s, r) = counter::new(flavors::zero::Channel::new());
116	        let s = Sender {
117	            flavor: SenderFlavor::Zero(s),
118	        };
119	        let r = Receiver {
120	            flavor: ReceiverFlavor::Zero(r),
121	        };
122	        (s, r)
123	    } else {
124	        let (s, r) = counter::new(flavors::array::Channel::with_capacity(cap));
125	        let s = Sender {
126	            flavor: SenderFlavor::Array(s),
127	        };
128	        let r = Receiver {
129	            flavor: ReceiverFlavor::Array(r),
130	        };
131	        (s, r)
132	    }
133	}
134	
135	/// Creates a receiver that delivers a message after a certain duration of time.
136	///
137	/// The channel is bounded with capacity of 1 and never gets disconnected. Exactly one message will
138	/// be sent into the channel after `duration` elapses. The message is the instant at which it is
139	/// sent.
140	///
141	/// # Examples
142	///
143	/// Using an `after` channel for timeouts:
144	///
145	/// ```
146	/// use std::time::Duration;
147	/// use crossbeam_channel::{after, select, unbounded};
148	///
149	/// let (s, r) = unbounded::<i32>();
150	/// let timeout = Duration::from_millis(100);
151	///
152	/// select! {
153	///     recv(r) -> msg => println!("received {:?}", msg),
154	///     recv(after(timeout)) -> _ => println!("timed out"),
155	/// }
156	/// ```
157	///
158	/// When the message gets sent:
159	///
160	/// ```
161	/// # if cfg!(gha_macos_runner) { return; } // GitHub-hosted macOS runner is slow
162	/// use std::thread;
163	/// use std::time::{Duration, Instant};
164	/// use crossbeam_channel::after;
165	///
166	/// // Converts a number of milliseconds into a `Duration`.
167	/// let ms = |ms| Duration::from_millis(ms);
168	///
169	/// // Returns `true` if `a` and `b` are very close `Instant`s.
170	/// let eq = |a, b| a + ms(60) > b && b + ms(60) > a;
171	///
172	/// let start = Instant::now();
173	/// let r = after(ms(100));
174	///
175	/// thread::sleep(ms(500));
176	///
177	/// // This message was sent 100 ms from the start and received 500 ms from the start.
178	/// assert!(eq(r.recv().unwrap(), start + ms(100)));
179	/// assert!(eq(Instant::now(), start + ms(500)));
180	/// ```
181	pub fn after(duration: Duration) -> Receiver<Instant> {
182	    match Instant::now().checked_add(duration) {
183	        Some(deadline) => Receiver {
184	            flavor: ReceiverFlavor::At(Arc::new(flavors::at::Channel::new_deadline(deadline))),
185	        },
186	        None => never(),
187	    }
188	}
189	
190	/// Creates a receiver that delivers a message at a certain instant in time.
191	///
192	/// The channel is bounded with capacity of 1 and never gets disconnected. Exactly one message will
193	/// be sent into the channel at the moment in time `when`. The message is the instant at which it
194	/// is sent, which is the same as `when`. If `when` is in the past, the message will be delivered
195	/// instantly to the receiver.
196	///
197	/// # Examples
198	///
199	/// Using an `at` channel for timeouts:
200	///
201	/// ```
202	/// use std::time::{Instant, Duration};
203	/// use crossbeam_channel::{at, select, unbounded};
204	///
205	/// let (s, r) = unbounded::<i32>();
206	/// let deadline = Instant::now() + Duration::from_millis(500);
207	///
208	/// select! {
209	///     recv(r) -> msg => println!("received {:?}", msg),
210	///     recv(at(deadline)) -> _ => println!("timed out"),
211	/// }
212	/// ```
213	///
214	/// When the message gets sent:
215	///
216	/// ```
217	/// use std::time::{Duration, Instant};
218	/// use crossbeam_channel::at;
219	///
220	/// // Converts a number of milliseconds into a `Duration`.
221	/// let ms = |ms| Duration::from_millis(ms);
222	///
223	/// let start = Instant::now();
224	/// let end = start + ms(100);
225	///
226	/// let r = at(end);
227	///
228	/// // This message was sent 100 ms from the start
229	/// assert_eq!(r.recv().unwrap(), end);
230	/// assert!(Instant::now() > start + ms(100));
231	/// ```
232	pub fn at(when: Instant) -> Receiver<Instant> {
233	    Receiver {
234	        flavor: ReceiverFlavor::At(Arc::new(flavors::at::Channel::new_deadline(when))),
235	    }
236	}
237	
238	/// Creates a receiver that never delivers messages.
239	///
240	/// The channel is bounded with capacity of 0 and never gets disconnected.
241	///
242	/// # Examples
243	///
244	/// Using a `never` channel to optionally add a timeout to [`select!`]:
245	///
246	/// [`select!`]: crate::select!
247	///
248	/// ```
249	/// use std::thread;
250	/// use std::time::Duration;
251	/// use crossbeam_channel::{after, select, never, unbounded};
252	///
253	/// let (s, r) = unbounded();
254	///
255	/// # let t =
256	/// thread::spawn(move || {
257	///     thread::sleep(Duration::from_secs(1));
258	///     s.send(1).unwrap();
259	/// });
260	///
261	/// // Suppose this duration can be a `Some` or a `None`.
262	/// let duration = Some(Duration::from_millis(100));
263	///
264	/// // Create a channel that times out after the specified duration.
265	/// let timeout = duration
266	///     .map(after)
267	///     .unwrap_or_else(never);
268	///
269	/// select! {
270	///     recv(r) -> msg => assert_eq!(msg, Ok(1)),
271	///     recv(timeout) -> _ => println!("timed out"),
272	/// }
273	/// # t.join().unwrap(); // join thread to avoid https://github.com/rust-lang/miri/issues/1371
274	/// ```
275	pub const fn never<T>() -> Receiver<T> {
276	    Receiver {
277	        flavor: ReceiverFlavor::Never(flavors::never::Channel::new()),
278	    }
279	}
280	
281	/// Creates a receiver that delivers messages periodically.
282	///
283	/// The channel is bounded with capacity of 1 and never gets disconnected. Messages will be
284	/// sent into the channel in intervals of `duration`. Each message is the instant at which it is
285	/// sent.
286	///
287	/// # Examples
288	///
289	/// Using a `tick` channel to periodically print elapsed time:
290	///
291	/// ```
292	/// use std::time::{Duration, Instant};
293	/// use crossbeam_channel::tick;
294	///
295	/// let start = Instant::now();
296	/// let ticker = tick(Duration::from_millis(100));
297	///
298	/// for _ in 0..5 {
299	///     ticker.recv().unwrap();
300	///     println!("elapsed: {:?}", start.elapsed());
301	/// }
302	/// ```
303	///
304	/// When messages get sent:
305	///
306	/// ```
307	/// # if cfg!(gha_macos_runner) { return; } // GitHub-hosted macOS runner is slow
308	/// use std::thread;
309	/// use std::time::{Duration, Instant};
310	/// use crossbeam_channel::tick;
311	///
312	/// // Converts a number of milliseconds into a `Duration`.
313	/// let ms = |ms| Duration::from_millis(ms);
314	///
315	/// // Returns `true` if `a` and `b` are very close `Instant`s.
316	/// let eq = |a, b| a + ms(65) > b && b + ms(65) > a;
317	///
318	/// let start = Instant::now();
319	/// let r = tick(ms(100));
320	///
321	/// // This message was sent 100 ms from the start and received 100 ms from the start.
322	/// assert!(eq(r.recv().unwrap(), start + ms(100)));
323	/// assert!(eq(Instant::now(), start + ms(100)));
324	///
325	/// thread::sleep(ms(500));
326	///
327	/// // This message was sent 200 ms from the start and received 600 ms from the start.
328	/// assert!(eq(r.recv().unwrap(), start + ms(200)));
329	/// assert!(eq(Instant::now(), start + ms(600)));
330	///
331	/// // This message was sent 700 ms from the start and received 700 ms from the start.
332	/// assert!(eq(r.recv().unwrap(), start + ms(700)));
333	/// assert!(eq(Instant::now(), start + ms(700)));
334	/// ```
335	pub fn tick(duration: Duration) -> Receiver<Instant> {
336	    match Instant::now().checked_add(duration) {
337	        Some(delivery_time) => Receiver {
338	            flavor: ReceiverFlavor::Tick(Arc::new(flavors::tick::Channel::new(
339	                delivery_time,
340	                duration,
341	            ))),
342	        },
343	        None => never(),
344	    }
345	}
346	
347	/// The sending side of a channel.
348	///
349	/// # Examples
350	///
351	/// ```
352	/// use std::thread;
353	/// use crossbeam_channel::unbounded;
354	///
355	/// let (s1, r) = unbounded();
356	/// let s2 = s1.clone();
357	///
358	/// thread::spawn(move || s1.send(1).unwrap());
359	/// thread::spawn(move || s2.send(2).unwrap());
360	///
361	/// let msg1 = r.recv().unwrap();
362	/// let msg2 = r.recv().unwrap();
363	///
364	/// assert_eq!(msg1 + msg2, 3);
365	/// ```
366	pub struct Sender<T> {
367	    flavor: SenderFlavor<T>,
368	}
369	
370	/// Sender flavors.
371	enum SenderFlavor<T> {
372	    /// Bounded channel based on a preallocated array.
373	    Array(counter::Sender<flavors::array::Channel<T>>),
374	
375	    /// Unbounded channel implemented as a linked list.
376	    List(counter::Sender<flavors::list::Channel<T>>),
377	
378	    /// Zero-capacity channel.
379	    Zero(counter::Sender<flavors::zero::Channel<T>>),
380	}
381	
382	unsafe impl<T: Send> Send for Sender<T> {}
383	unsafe impl<T: Send> Sync for Sender<T> {}
384	
385	impl<T> UnwindSafe for Sender<T> {}
386	impl<T> RefUnwindSafe for Sender<T> {}
387	
388	impl<T> Sender<T> {
389	    /// Attempts to send a message into the channel without blocking.
390	    ///
391	    /// This method will either send a message into the channel immediately or return an error if
392	    /// the channel is full or disconnected. The returned error contains the original message.
393	    ///
394	    /// If called on a zero-capacity channel, this method will send the message only if there
395	    /// happens to be a receive operation on the other side of the channel at the same time.
396	    ///
397	    /// # Examples
398	    ///
399	    /// ```
400	    /// use crossbeam_channel::{bounded, TrySendError};
401	    ///
402	    /// let (s, r) = bounded(1);
403	    ///
404	    /// assert_eq!(s.try_send(1), Ok(()));
405	    /// assert_eq!(s.try_send(2), Err(TrySendError::Full(2)));
406	    ///
407	    /// drop(r);
408	    /// assert_eq!(s.try_send(3), Err(TrySendError::Disconnected(3)));
409	    /// ```
410	    pub fn try_send(&self, msg: T) -> Result<(), TrySendError<T>> {
411	        match &self.flavor {
412	            SenderFlavor::Array(chan) => chan.try_send(msg),
413	            SenderFlavor::List(chan) => chan.try_send(msg),
414	            SenderFlavor::Zero(chan) => chan.try_send(msg),
415	        }
416	    }
417	
418	    /// Blocks the current thread until a message is sent or the channel is disconnected.
419	    ///
420	    /// If the channel is full and not disconnected, this call will block until the send operation
421	    /// can proceed. If the channel becomes disconnected, this call will wake up and return an
422	    /// error. The returned error contains the original message.
423	    ///
424	    /// If called on a zero-capacity channel, this method will wait for a receive operation to
425	    /// appear on the other side of the channel.
426	    ///
427	    /// # Examples
428	    ///
429	    /// ```
430	    /// use std::thread;
431	    /// use std::time::Duration;
432	    /// use crossbeam_channel::{bounded, SendError};
433	    ///
434	    /// let (s, r) = bounded(1);
435	    /// assert_eq!(s.send(1), Ok(()));
436	    ///
437	    /// thread::spawn(move || {
438	    ///     assert_eq!(r.recv(), Ok(1));
439	    ///     thread::sleep(Duration::from_secs(1));
440	    ///     drop(r);
441	    /// });
442	    ///
443	    /// assert_eq!(s.send(2), Ok(()));
444	    /// assert_eq!(s.send(3), Err(SendError(3)));
445	    /// ```
446	    pub fn send(&self, msg: T) -> Result<(), SendError<T>> {
447	        match &self.flavor {
448	            SenderFlavor::Array(chan) => chan.send(msg, None),
449	            SenderFlavor::List(chan) => chan.send(msg, None),
450	            SenderFlavor::Zero(chan) => chan.send(msg, None),
451	        }
452	        .map_err(|err| match err {
453	            SendTimeoutError::Disconnected(msg) => SendError(msg),
454	            SendTimeoutError::Timeout(_) => unreachable!(),
455	        })
456	    }
457	
458	    /// Waits for a message to be sent into the channel, but only for a limited time.
459	    ///
460	    /// If the channel is full and not disconnected, this call will block until the send operation
461	    /// can proceed or the operation times out. If the channel becomes disconnected, this call will
462	    /// wake up and return an error. The returned error contains the original message.
463	    ///
464	    /// If called on a zero-capacity channel, this method will wait for a receive operation to
465	    /// appear on the other side of the channel.
466	    ///
467	    /// # Examples
468	    ///
469	    /// ```
470	    /// use std::thread;
471	    /// use std::time::Duration;
